<h1 class="h3 mb-1">Document versions</h1><p class="text-muted mb-4">Immutable history for generated and uploaded business documents.</p><div class="card"><div class="card-body"><div class="table-responsive"><table class="table"><thead><tr><th>Document</th><th>Version</th><th>SHA-256</th><th>Size</th><th>Notes</th><th>Created</th></tr></thead><tbody><?php foreach($versions as $v):?><tr><td><?=e($v['document_type'].' #'.$v['document_id'])?></td><td>v<?=e($v['version_number'])?></td><td><code><?=e(substr((string)$v['sha256'],0,16))?>…</code></td><td><?=number_format(((int)$v['file_size'])/1024,1)?> KB</td><td><?=e($v['change_notes'])?></td><td><?=e($v['created_at'])?></td></tr><?php endforeach?></tbody></table></div></div></div>
